#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>

static const uint64_t MOD = 4294967143ULL;

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        uint64_t dp[65][11] = {{0}};
        for (int j = 1; j <= 10; j++) {
            dp[1][j] = 1;
        }
        for (int i = 2; i <= N; i++) {
            for (int j = 0; j <= 10; j++) {
                for (int k = 0; k <= 10; k++) {
                    if (j == k || abs(j - k) == 1) {
                        dp[i][j] = (dp[i][j] + dp[i - 1][k]) % MOD;
                    }
                }
            }
        }
        uint64_t ans = 0;
        for (int j = 0; j <= 10; j++) {
            ans = (ans + dp[N][j]) % MOD;
        }
        printf("%llu\n", ans);
    }
    return 0;
}

